#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#define MOD 1000000007
#define MAXN 50
#define MAXK 10000
#define MAXT 50
// Function to calculate the number of ways the training can end within Ki steps or less
long long calculate_ways(int T, int Nk, int Mk, int Li, int Ri, int Ki) {
    // Initialize the dynamic programming table
    long long dp[MAXN][MAXK + 1];
    // Initialize the base case
    for (int i = 0; i < Nk; i++) {
        dp[i][0] = 1;
    }
    // Calculate the number of ways the training can end within Ki steps or less
    for (int k = 1; k <= Ki; k++) {
        for (int i = 0; i < Nk; i++) {
            dp[i][k] = 0;
            for (int j = 0; j < Nk; j++) {
                if (i != j) {
                    dp[i][k] += dp[j][k - 1];
                    dp[i][k] %= MOD;
                }
            }
        }
    }
    // Calculate the final result
    long long result = 0;
    for (int i = 0; i < Nk; i++) {
        result += dp[i][Ki];
        result %= MOD;
    }
    return result;
}
int main() {
    int T;
    scanf("%d", &T);
    int Nk[T], Mk[T];
    for (int i = 0; i < T; i++) {
        scanf("%d %d", &Nk[i], &Mk[i]);
    }
    int Q;
    scanf("%d", &Q);
    for (int i = 0; i < Q; i++) {
        int Li, Ri, Ki;
        scanf("%d %d %d", &Li, &Ri, &Ki);
